import React from "react";

import UserItem from './UserItem';
import './UsersList.css';

const UsersList = props => {
    if (props.item.length === 0) {
        return (
          <div className="center">
            <card>
            <h2>No User found.</h2>
            </card>
        </div>
        );
    }

    return (
    <ul>
        {props.item.map(user => (
          <UserItem 
            key={user.id} 
            id={user.id} 
            image={user.image} 
            name={user.name}  
            placeCount={user.places}
            />
        ))}
    </ul>
    );
};

export default UsersList;
